const durH   = (s,e) => (new Date(e)-new Date(s))/3600000;
const overlap= (s1,e1,s2,e2) => new Date(s1)<new Date(e2) && new Date(s2)<new Date(e1);
const isJira = (k) => /^[A-Z][A-Z0-9]+-\d+$/.test((k||"").trim());

const checkOverlap = (ress, envId, s, e, excId) =>
  ress.filter(r => r.environmentId===envId && r.id!==excId &&
    ["Reserved","InUse","PolicyViolation"].includes(r.status) && overlap(s,e,r.plannedStart,r.plannedEnd));

const autoRelease = (ress) => {
  const n = new Date();
  return ress.map(r => {
    if(["Reserved","InUse"].includes(r.status) && new Date(r.plannedEnd)<=n)
      return { ...r, status:"Completed",
        usageSession: r.usageSession
          ? {...r.usageSession, actualEnd:r.plannedEnd}
          : {actualStart:r.plannedStart, actualEnd:r.plannedEnd, branches:[]} };
    return r;
  });
};

const parseCsv = (text) => {
  const lines = text.trim().split(/\r?\n/).filter(Boolean);
  if(!lines.length) return [];
  const hdr = lines[0].split(",").map(s=>s.trim().toLowerCase());
  const ni = hdr.includes("name") ? hdr.indexOf("name") : 0;
  return lines.slice(1).map(l=>{
    const cols = l.split(",").map(s=>s.trim().replace(/^"|"$/g,""));
    const name = cols[ni];
    return name ? {id:uid(), name, isArchived:false} : null;
  }).filter(Boolean);
};

