function MultiSelect({options, value, onChange, placeholder="Select…", t}) {
  const [open,setOpen]   = useState(false);
  const [q,setQ]         = useState("");
  const ref              = useRef();

  useEffect(() => {
    const h = e => { if(ref.current&&!ref.current.contains(e.target)) { setOpen(false); setQ(""); } };
    document.addEventListener("mousedown",h);
    return () => document.removeEventListener("mousedown",h);
  },[]);

  const filtered = options.filter(o => o.name.toLowerCase().includes(q.toLowerCase()));
  const toggle = id => onChange(value.includes(id) ? value.filter(v=>v!==id) : [...value,id]);
  const selected = options.filter(o=>value.includes(o.id));

  return (
    <div ref={ref} style={{position:"relative",width:"100%"}}>
      <div onClick={()=>setOpen(o=>!o)} style={{...I(t),cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"space-between",minHeight:38,userSelect:"none"}}>
        <span style={{flex:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",color:selected.length?t.text:t.muted,fontSize:13}}>
          {selected.length ? selected.map(o=>o.name).join(", ") : placeholder}
        </span>
        <span style={{display:"flex",alignItems:"center",gap:4,marginLeft:6,flexShrink:0}}>
          {value.length>0 && <span style={{background:t.accent,color:"#fff",borderRadius:10,padding:"1px 6px",fontSize:10}}>{value.length}</span>}
          <span style={{color:t.muted,fontSize:10}}>{open?"▲":"▼"}</span>
        </span>
      </div>
      {open && (
        <div style={{position:"absolute",top:"calc(100%+4px)",left:0,right:0,zIndex:300,background:t.surface,border:`1px solid ${t.border}`,borderRadius:10,boxShadow:`0 8px 32px ${t.shadow}`,overflow:"hidden",marginTop:4}}>
          <div style={{padding:"8px 10px",borderBottom:`1px solid ${t.border}`}}>
            <input autoFocus value={q} onChange={e=>setQ(e.target.value)} placeholder="Search repositories…"
              style={{...I(t,{padding:"6px 10px",fontSize:12})}} onClick={e=>e.stopPropagation()}/>
          </div>
          <div style={{maxHeight:180,overflowY:"auto"}}>
            {filtered.length===0 && <div style={{padding:"10px 14px",color:t.muted,fontSize:13}}>No results for "{q}"</div>}
            {filtered.map(o => (
              <div key={o.id} onClick={()=>toggle(o.id)}
                style={{display:"flex",alignItems:"center",gap:10,padding:"8px 12px",cursor:"pointer",background:value.includes(o.id)?t.accent+"18":"transparent",transition:"background 0.1s"}}
                onMouseEnter={e=>e.currentTarget.style.background=value.includes(o.id)?t.accent+"28":t.border+"50"}
                onMouseLeave={e=>e.currentTarget.style.background=value.includes(o.id)?t.accent+"18":"transparent"}>
                <div style={{width:15,height:15,borderRadius:4,border:`2px solid ${value.includes(o.id)?t.accent:t.muted}`,background:value.includes(o.id)?t.accent:"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                  {value.includes(o.id)&&<span style={{color:"#fff",fontSize:9,lineHeight:1}}>✓</span>}
                </div>
                <span style={{fontSize:13,color:t.text}}>{o.name}</span>
              </div>
            ))}
          </div>
          {value.length>0&&(
            <div style={{borderTop:`1px solid ${t.border}`,padding:"6px 12px"}}>
              <button onClick={()=>{onChange([]);setQ("");}} style={{...B(t,"ghost",{fontSize:11,padding:"2px 8px",color:"#ef4444"})}}>Clear all</button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function JiraTagInput({value, onChange, t}) {
  const [draft,setDraft] = useState("");
  const [err,setErr]     = useState("");
  const add = k => {
    const key = (k||"").trim().toUpperCase();
    if(!key) return;
    if(!isJira(key)){setErr(`Invalid: "${key}" — use PROJECT-123`);return;}
    if(value.includes(key)){setErr("Already added");return;}
    onChange([...value,key]); setDraft(""); setErr("");
  };
  return (
    <div>
      <div style={{...I(t,{minHeight:42,display:"flex",flexWrap:"wrap",gap:4,alignItems:"center",padding:"6px 10px",cursor:"text"})}}
        onClick={()=>document.getElementById("jtag")?.focus()}>
        {value.map(k=>(
          <span key={k} style={{background:t.accent+"22",color:t.accent,padding:"2px 8px",borderRadius:6,fontSize:12,fontFamily:"'JetBrains Mono',monospace",display:"flex",alignItems:"center",gap:4}}>
            {k}<span onClick={()=>onChange(value.filter(v=>v!==k))} style={{cursor:"pointer",opacity:0.7,fontSize:14,lineHeight:1}}>×</span>
          </span>
        ))}
        <input id="jtag" value={draft}
          onChange={e=>{setDraft(e.target.value.toUpperCase());setErr("");}}
          onKeyDown={e=>{
            if(["Enter","Tab",","," "].includes(e.key)){e.preventDefault();add(draft);}
            if(e.key==="Backspace"&&!draft&&value.length) onChange(value.slice(0,-1));
          }}
          onBlur={()=>{if(draft.trim()) add(draft);}}
          placeholder={value.length?"":"PROJ-123 → Enter to add"}
          style={{background:"transparent",border:"none",outline:"none",fontSize:13,color:t.text,fontFamily:"'JetBrains Mono',monospace",flex:1,minWidth:140,padding:"2px 0"}}/>
      </div>
      <Err m={err}/>
    </div>
  );
}

