function AvailabilityDatePicker({label, value, onChange, ress, envId, excludeId, t}) {
  const parsedDate = value ? new Date(value) : null;
  const [open, setOpen] = useState(false);
  const [viewYear,  setViewYear]  = useState((parsedDate||new Date()).getFullYear());
  const [viewMonth, setViewMonth] = useState((parsedDate||new Date()).getMonth());
  const [timeVal,   setTimeVal]   = useState(
    parsedDate
      ? `${String(parsedDate.getHours()).padStart(2,"0")}:${String(parsedDate.getMinutes()).padStart(2,"0")}`
      : "09:00"
  );

  const triggerRef = useRef();
  const panelRef   = useRef();
  const [coords, setCoords] = useState({top:0,left:0});

  useEffect(()=>{
    const h = e => {
      if(open &&
         triggerRef.current && !triggerRef.current.contains(e.target) &&
         panelRef.current   && !panelRef.current.contains(e.target)) {
        setOpen(false);
      }
    };
    document.addEventListener("mousedown", h);
    return ()=>document.removeEventListener("mousedown", h);
  },[open]);

  const busyDays = useMemo(()=>{
    if(!envId) return new Set();
    const busy = new Set();
    ress
      .filter(r => r.environmentId===envId && r.id!==excludeId && ["Reserved","InUse","PolicyViolation"].includes(r.status))
      .forEach(r => {
        let cur = new Date(r.plannedStart); cur.setHours(0,0,0,0);
        const end = new Date(r.plannedEnd);
        while(cur <= end) {
          busy.add(`${cur.getFullYear()}-${cur.getMonth()}-${cur.getDate()}`);
          cur = new Date(cur.getTime() + 86400000);
        }
      });
    return busy;
  }, [ress, envId, excludeId]);

  const today = useMemo(()=>{ const d=new Date(); d.setHours(0,0,0,0); return d; },[]);

  const firstWeekday = new Date(viewYear, viewMonth, 1).getDay();
  const startOffset  = (firstWeekday + 6) % 7;
  const daysInMonth  = new Date(viewYear, viewMonth+1, 0).getDate();

  const applySelection = (day, newTime) => {
    const d = new Date(viewYear, viewMonth, day);
    const [hh,mm] = (newTime||timeVal).split(":").map(Number);
    d.setHours(hh, mm, 0, 0);
    const pad = n=>String(n).padStart(2,"0");
    const str = `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(hh)}:${pad(mm)}`;
    onChange(str);
    setOpen(false);
  };

  const handleTimeChange = newTime => {
    setTimeVal(newTime);
    if(parsedDate) {
      const d = new Date(parsedDate);
      const [hh,mm] = newTime.split(":").map(Number);
      d.setHours(hh, mm, 0, 0);
      const pad = n=>String(n).padStart(2,"0");
      const str = `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(hh)}:${pad(mm)}`;
      onChange(str);
    }
  };

  const openPicker = () => {
    if(triggerRef.current) {
      const r = triggerRef.current.getBoundingClientRect();
      const spaceBelow = window.innerHeight - r.bottom;
      const panelH = 310;
      const top = spaceBelow > panelH ? r.bottom + 4 : r.top - panelH - 4;
      const left = Math.min(r.left, window.innerWidth - 268);
      setCoords({top, left});
    }
    setOpen(o=>!o);
  };

  const display = parsedDate
    ? parsedDate.toLocaleString("es-ES",{timeZone:"Europe/Madrid",dateStyle:"short",timeStyle:"short"})
    : "Seleccionar…";

  return (
    <>
      <div ref={triggerRef} onClick={openPicker}
        style={{...I(t,{cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"space-between",userSelect:"none"}),
          borderColor: open ? t.accent : t.inputBorder}}>
        <span style={{color: parsedDate ? t.text : t.muted, fontSize:13}}>{display}</span>
        <span style={{fontSize:13, color:t.muted, marginLeft:6}}>📅</span>
      </div>

      {open && (
        <div ref={panelRef}
          style={{position:"fixed",top:coords.top,left:coords.left,width:260,zIndex:9998,
            background:t.surface,border:`1px solid ${t.border}`,borderRadius:12,
            boxShadow:`0 16px 48px rgba(0,0,0,0.55)`,padding:12}}>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
            <button onClick={()=>{ if(viewMonth===0){setViewMonth(11);setViewYear(y=>y-1);}else setViewMonth(m=>m-1); }}
              style={B(t,"ghost",{padding:"2px 8px",fontSize:15,lineHeight:1})}>‹</button>
            <span style={{fontWeight:700,fontSize:13,color:t.text}}>{MONTHS_ES[viewMonth]} {viewYear}</span>
            <button onClick={()=>{ if(viewMonth===11){setViewMonth(0);setViewYear(y=>y+1);}else setViewMonth(m=>m+1); }}
              style={B(t,"ghost",{padding:"2px 8px",fontSize:15,lineHeight:1})}>›</button>
          </div>

          <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",marginBottom:4}}>
            {DAYS_ES.map(d=>(
              <div key={d} style={{textAlign:"center",fontSize:10,fontWeight:700,color:t.muted,padding:"2px 0"}}>{d}</div>
            ))}
          </div>

          <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:2}}>
            {Array.from({length:startOffset}).map((_,i)=><div key={"e"+i}/>)}
            {Array.from({length:daysInMonth}).map((_,i)=>{
              const day      = i+1;
              const dayDate  = new Date(viewYear, viewMonth, day);
              const dayKey   = `${viewYear}-${viewMonth}-${day}`;
              const isPast   = dayDate < today;
              const isBusy   = !isPast && envId && busyDays.has(dayKey);
              const isSel    = parsedDate &&
                               parsedDate.getFullYear()===viewYear &&
                               parsedDate.getMonth()===viewMonth &&
                               parsedDate.getDate()===day;
              const isToday  = dayDate.getTime()===today.getTime();

              let bg="transparent",fg=t.text,brd="transparent",cursor="pointer";
              if(isSel){bg=t.accent;fg="#fff";}
              else if(isPast){fg=t.muted+"55";cursor="default";}
              else if(isBusy){bg="rgba(239,68,68,0.18)";fg="#f87171";brd="rgba(239,68,68,0.4)";cursor="not-allowed";}
              else{bg="rgba(34,197,94,0.15)";fg="#4ade80";brd="rgba(34,197,94,0.35)";}
              if(isToday&&!isSel) brd=t.accent;

              return (
                <div key={day} title={!envId?"":isBusy?"Ocupado":"Disponible"}
                  onClick={()=>{ if(!isPast&&!isBusy) applySelection(day); }}
                  style={{textAlign:"center",padding:"4px 0",borderRadius:6,fontSize:12,
                    fontWeight:isSel||isToday?700:400,background:bg,color:fg,cursor,
                    border:`1px solid ${brd}`,transition:"all 0.1s"}}>
                  {day}
                </div>
              );
            })}
          </div>

          <div style={{marginTop:10,paddingTop:10,borderTop:`1px solid ${t.border}`,display:"flex",alignItems:"center",gap:8}}>
            <span style={{fontSize:11,color:t.muted,fontWeight:600,textTransform:"uppercase",letterSpacing:"0.04em",whiteSpace:"nowrap"}}>Hora</span>
            <input type="time" value={timeVal} onChange={e=>handleTimeChange(e.target.value)}
              style={{...I(t,{flex:1,padding:"5px 8px",fontSize:13})}}/>
          </div>

          {envId && (
            <div style={{display:"flex",gap:14,marginTop:8,fontSize:10}}>
              <span style={{display:"flex",alignItems:"center",gap:4,color:"#4ade80"}}>
                <span style={{width:10,height:10,borderRadius:3,background:"rgba(34,197,94,0.2)",border:"1px solid #4ade80",display:"inline-block"}}/>
                Disponible
              </span>
              <span style={{display:"flex",alignItems:"center",gap:4,color:"#f87171"}}>
                <span style={{width:10,height:10,borderRadius:3,background:"rgba(239,68,68,0.2)",border:"1px solid #f87171",display:"inline-block"}}/>
                Ocupado
              </span>
            </div>
          )}
          {!envId && (
            <div style={{marginTop:8,fontSize:11,color:t.muted}}>
              Selecciona un entorno primero para ver disponibilidad
            </div>
          )}
        </div>
      )}
    </>
  );
}

function ResForm({res, envs, repos, ress, currentUser, policy, onSave, onClose, t}) {
  const isEdit = !!res;
  const [envId,  setEnvId]  = useState(res?.environmentId||"");
  const [jiras,  setJiras]  = useState(res?.jiraIssueKeys||[]);
  const [desc,   setDesc]   = useState(res?.description||"");
  const [start,  setStart]  = useState(res?.plannedStart?res.plannedStart.slice(0,16):"");
  const [end,    setEnd]    = useState(res?.plannedEnd?res.plannedEnd.slice(0,16):"");
  const [rids,   setRids]   = useState(res?.selectedRepositoryIds||[]);
  const [errors, setErrors] = useState({});
  const selEnv = envs.find(e=>e.id===envId);
  const isAdmin = currentUser.role==="ADMIN";

  const validate = () => {
    const e={};
    if(!envId)         e.env="Select an environment";
    if(!jiras.length)  e.jiras="Add at least one Jira key";
    if(selEnv?.isLocked && !isAdmin) e.env="Este entorno está bloqueado por el administrador";
    if(!start)         e.start="Required";
    if(!end)           e.end="Required";
    if(start && end) {
      const sD=new Date(start), eD=new Date(end), n=new Date();
      if(sD>=eD)                 e.end="End must be after start";
      else if(eD<=n)             e.end="End must be in the future";
      else {
        if(!isAdmin && policy.bookingWindowDays) {
          const maxFuture = new Date(n.getTime() + policy.bookingWindowDays*86400000);
          if(eD > maxFuture) e.end=`Can't book more than ${policy.bookingWindowDays} days ahead (policy)`;
        }
        if(selEnv && !e.end) {
          const dur = durH(start,end);
          if(dur > selEnv.maxReservationDuration) e.end=`Exceeds env max ${selEnv.maxReservationDuration}h`;
          if(dur < policy.minDurationHours) e.end=`Min duration is ${policy.minDurationHours}h`;
        }
        if(envId && !e.end) {
          const ov = checkOverlap(ress, envId, start, end, res?.id);
          if(ov.length) e.overlap=`Overlaps: ${ov.map(r=>r.jiraIssueKeys.join(",")).join(" / ")}`;
        }
      }
    }
    return e;
  };

  const handleSave = () => {
    const errs = validate();
    if(Object.keys(errs).length){setErrors(errs);return;}
    const sD=new Date(start),n=new Date();
    let status = isEdit ? res.status : sD<=n ? "InUse":"Reserved";
    let session = isEdit ? res.usageSession : sD<=n ? {actualStart:sD.toISOString(),actualEnd:null,branches:[]} : null;
    if(isEdit && ["Reserved","PolicyViolation"].includes(res.status)){status=res.status;session=res.usageSession;}
    onSave({
      id:res?.id||uid(), environmentId:envId,
      reservedByUserId:res?.reservedByUserId||currentUser.id,
      jiraIssueKeys:jiras, description:desc.trim(),
      plannedStart:new Date(start).toISOString(), plannedEnd:new Date(end).toISOString(),
      status, selectedRepositoryIds:rids, usageSession:session, policyFlags:{exceedsMaxDuration:false},
    });
  };

  return (
    <Lay onClose={onClose}>
      <div style={modal(t)}>
        <MHead title={isEdit?"Edit Reservation":"New Reservation"} onClose={onClose} t={t}/>
        <div style={{padding:20}}>
          <div style={{marginBottom:14}}>
            <Lbl c="Environment" t={t}/>
            <select style={I(t)} value={envId} onChange={e=>setEnvId(e.target.value)}>
              <option value="">Select environment…</option>
              {envs.filter(e=>!e.isArchived && (isAdmin || !e.isLocked)).map(e=>(
                <option key={e.id} value={e.id}>
                  {e.isLocked?"🔒 ":""}{e.name} ({e.category}) — max {e.maxReservationDuration}h
                </option>
              ))}
            </select>
            {selEnv?.isLocked && isAdmin && (
              <div style={{marginTop:6,background:"rgba(251,191,36,0.1)",border:"1px solid rgba(251,191,36,0.35)",borderRadius:7,padding:"6px 10px",fontSize:12,color:"#fbbf24"}}>
                🔒 Entorno bloqueado — solo tú (admin) puedes reservarlo
              </div>
            )}
            <Err m={errors.env}/>
          </div>
          <div style={{marginBottom:14}}>
            <Lbl c="Jira Issue Keys" t={t}/>
            <JiraTagInput value={jiras} onChange={setJiras} t={t}/>
            <p style={{fontSize:11,color:t.muted,marginTop:3}}>Press Enter · Tab · Space after each key</p>
            <Err m={errors.jiras}/>
          </div>
          <div style={{marginBottom:14}}>
            <Lbl c="Description" t={t}/>
            <textarea value={desc} onChange={e=>setDesc(e.target.value)} rows={2}
              placeholder="Purpose of this reservation…"
              style={{...I(t,{resize:"vertical",lineHeight:1.55})}}/>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <div style={{marginBottom:14}}>
              <Lbl c="Planned Start" t={t}/>
              <AvailabilityDatePicker label="start" value={start} onChange={setStart} ress={ress} envId={envId} excludeId={res?.id} t={t}/>
              <Err m={errors.start}/>
            </div>
            <div style={{marginBottom:14}}>
              <Lbl c="Planned End" t={t}/>
              <AvailabilityDatePicker label="end" value={end} onChange={setEnd} ress={ress} envId={envId} excludeId={res?.id} t={t}/>
              <Err m={errors.end}/>
            </div>
          </div>
          {errors.overlap&&<div style={{background:"rgba(239,68,68,0.1)",border:"1px solid rgba(239,68,68,0.3)",borderRadius:8,padding:"8px 12px",color:"#ef4444",fontSize:12,marginBottom:12}}>⛔ {errors.overlap}</div>}
          <div style={{marginBottom:14}}>
            <Lbl c="Repositories" t={t}/>
            <MultiSelect options={repos.filter(r=>!r.isArchived)} value={rids} onChange={setRids} placeholder="Search & select repositories…" t={t}/>
          </div>
          <div style={{display:"flex",justifyContent:"flex-end",gap:8,marginTop:8}}>
            <button style={B(t,"ghost")} onClick={onClose}>Cancel</button>
            <button style={B(t)} onClick={handleSave}>{isEdit?"Update":"Create Reservation"}</button>
          </div>
        </div>
      </div>
    </Lay>
  );
}

function ResDetail({res, envs, repos, users, currentUser, onClose, onEdit, onCancel, onCheckIn, onCheckOut, onAddBranch, t}) {
  const env     = envs.find(e=>e.id===res.environmentId);
  const owner   = users.find(u=>u.id===res.reservedByUserId);
  const isOwner = currentUser.id===res.reservedByUserId;
  const isAdmin = currentUser.role==="ADMIN";
  const [nb,setNb]   = useState("");
  const [showB,setShowB] = useState(false);
  const repoNames = res.selectedRepositoryIds.map(id=>repos.find(r=>r.id===id)?.name).filter(Boolean);

  const canEdit   = (isOwner||isAdmin) && ["Reserved","PolicyViolation","InUse"].includes(res.status);
  const canCI     = isOwner && res.status==="Reserved";
  const canCO     = isOwner && res.status==="InUse";
  const canCancel = (isOwner||isAdmin) && ["Reserved","InUse","PolicyViolation"].includes(res.status);

  const IR = ({l,v,mono}) => (
    <div style={{marginBottom:8}}>
      <span style={{fontSize:10,color:t.muted,fontWeight:700,display:"block",textTransform:"uppercase",letterSpacing:"0.04em"}}>{l}</span>
      <span style={{color:t.text,fontSize:13,fontFamily:mono?"'JetBrains Mono',monospace":"inherit"}}>{v||"—"}</span>
    </div>
  );

  return (
    <Lay onClose={onClose}>
      <div style={modal(t)}>
        <MHead title="Reservation Details" onClose={onClose} t={t}/>
        <div style={{padding:20}}>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14}}>
            <div style={{display:"flex",alignItems:"center",gap:8}}>
              <CatBadge cat={env?.category}/><span style={{fontWeight:700,fontSize:16,color:t.text}}>{env?.name}</span>
            </div>
            <SBadge status={res.status}/>
          </div>
          {res.policyFlags?.exceedsMaxDuration&&(
            <div style={{background:"rgba(249,115,22,0.1)",border:"1px solid rgba(249,115,22,0.3)",borderRadius:8,padding:"10px 14px",color:"#fb923c",fontSize:13,marginBottom:14}}>
              ⚠️ <strong>Needs admin attention</strong> — Exceeds environment's max duration policy.
            </div>
          )}
          <div style={{marginBottom:12}}>
            <span style={{fontSize:10,color:t.muted,fontWeight:700,display:"block",textTransform:"uppercase",letterSpacing:"0.04em",marginBottom:5}}>Jira Issues</span>
            <div style={{display:"flex",flexWrap:"wrap",gap:4}}>
              {(res.jiraIssueKeys||[]).map(k=><span key={k} style={{background:t.accent+"20",color:t.accent,padding:"3px 10px",borderRadius:6,fontSize:12,fontFamily:"'JetBrains Mono',monospace"}}>{k}</span>)}
            </div>
          </div>
          {res.description&&(
            <div style={{marginBottom:12,background:t.inputBg,border:`1px solid ${t.border}`,borderRadius:8,padding:"10px 12px"}}>
              <span style={{fontSize:10,color:t.muted,fontWeight:700,display:"block",textTransform:"uppercase",letterSpacing:"0.04em",marginBottom:4}}>Description</span>
              <span style={{color:t.text,fontSize:13,lineHeight:1.6}}>{res.description}</span>
            </div>
          )}
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:8}}>
            <IR l="Owner"         v={owner?.displayName||owner?.username}/>
            <IR l="Duration"      v={`${durH(res.plannedStart,res.plannedEnd).toFixed(1)}h`}/>
            <IR l="Planned Start" v={fmtDt(res.plannedStart)}/>
            <IR l="Planned End"   v={fmtDt(res.plannedEnd)}/>
            {res.usageSession&&<>
              <IR l="Actual Start" v={fmtDt(res.usageSession.actualStart)}/>
              <IR l="Actual End"   v={fmtDt(res.usageSession.actualEnd)||"—"}/>
            </>}
          </div>
          {repoNames.length>0&&(
            <div style={{marginBottom:10}}>
              <span style={{fontSize:10,color:t.muted,fontWeight:700,display:"block",textTransform:"uppercase",letterSpacing:"0.04em",marginBottom:4}}>Repositories</span>
              <div style={{display:"flex",flexWrap:"wrap",gap:4}}>
                {repoNames.map(n=><span key={n} style={{background:t.border,color:t.text,padding:"2px 8px",borderRadius:4,fontSize:12}}>📦 {n}</span>)}
              </div>
            </div>
          )}
          {res.usageSession?.branches?.length>0&&(
            <div style={{marginBottom:10}}>
              <span style={{fontSize:10,color:t.muted,fontWeight:700,display:"block",textTransform:"uppercase",letterSpacing:"0.04em",marginBottom:4}}>Branches</span>
              <div style={{display:"flex",flexWrap:"wrap",gap:4}}>
                {res.usageSession.branches.map(b=><span key={b} style={{background:"rgba(99,102,241,0.15)",color:"#a5b4fc",padding:"2px 8px",borderRadius:4,fontSize:12,fontFamily:"'JetBrains Mono',monospace"}}>{b}</span>)}
              </div>
            </div>
          )}
          {res.status==="InUse"&&isOwner&&(
            <div style={{marginTop:10,borderTop:`1px solid ${t.border}`,paddingTop:10}}>
              {showB ? (
                <div style={{display:"flex",gap:8}}>
                  <input style={{...I(t,{flex:1,fontFamily:"'JetBrains Mono',monospace"})}} value={nb} onChange={e=>setNb(e.target.value)} autoFocus placeholder="branch-name"
                    onKeyDown={e=>{if(e.key==="Enter"&&nb.trim()){onAddBranch(res.id,nb.trim());setNb("");setShowB(false);}}}/>
                  <button style={B(t)} onClick={()=>{if(nb.trim()){onAddBranch(res.id,nb.trim());setNb("");setShowB(false);}}}>Add</button>
                  <button style={B(t,"ghost")} onClick={()=>setShowB(false)}>×</button>
                </div>
              ):(
                <button style={B(t,"outline",{fontSize:12})} onClick={()=>setShowB(true)}>+ Add Branch</button>
              )}
            </div>
          )}
          {/* Access Environment button — always shown, disabled if no URL configured */}
          <div style={{marginTop:14,borderTop:`1px solid ${t.border}`,paddingTop:14}}>
            <div style={{display:"flex",flexWrap:"wrap",gap:8,marginBottom: (canEdit||canCI||canCO||canCancel) ? 10 : 0}}>
              {env?.url ? (
                <a href={env.url} target="_blank" rel="noopener noreferrer"
                  style={{...B(t,"blue"),display:"inline-flex",alignItems:"center",gap:6,textDecoration:"none",width:"100%",justifyContent:"center",padding:"9px 14px",fontSize:14,fontWeight:600,borderRadius:9}}>
                  🔗 Access Environment
                </a>
              ) : (
                <button disabled style={{...B(t,"ghost"),width:"100%",padding:"9px 14px",fontSize:14,fontWeight:600,borderRadius:9,opacity:0.4,cursor:"not-allowed",border:`1px dashed ${t.border}`,color:t.muted}}>
                  🔗 Access Environment — no URL configured
                </button>
              )}
            </div>
            {(canEdit||canCI||canCO||canCancel)&&(
              <div style={{display:"flex",flexWrap:"wrap",gap:8}}>
                {canEdit   && <button style={B(t)}           onClick={()=>onEdit(res)}>✏️ Edit</button>}
                {canCI     && <button style={B(t,"success")} onClick={()=>onCheckIn(res.id)}>▶ Check In</button>}
                {canCO     && <button style={B(t,"warning")} onClick={()=>onCheckOut(res.id)}>⏹ Check Out</button>}
                {canCancel && <button style={B(t,"danger")}  onClick={()=>onCancel(res.id)}>✕ Cancel</button>}
              </div>
            )}
          </div>
        </div>
      </div>
    </Lay>
  );
}

const PXH   = 80;
const ROW_H = 60;
const LBL_W = 148;
const DAY_H = 24;
const HR_H  = 22;
const HDR_H = DAY_H + HR_H;
const SNAP  = 0.5;

const SCALE_MODES = {
  hours:  { label:"Horas",   pxPerHour:160, windowH:24,    majorStep:1*3600000,    minorStep:null,          fmtMajor:d=>`${String(d.getHours()).padStart(2,"0")}:00`, fmtDay:d=>d.toLocaleDateString("es-ES",{weekday:"short",day:"numeric",month:"short"}) },
  days:   { label:"Días",    pxPerHour:80,  windowH:7*24,  majorStep:24*3600000,   minorStep:3*3600000,     fmtMajor:d=>String(d.getHours()).padStart(2,"0")+"h",     fmtDay:d=>d.toLocaleDateString("es-ES",{weekday:"short",day:"numeric",month:"short"}) },
  weeks:  { label:"Semanas", pxPerHour:20,  windowH:28*24, majorStep:24*3600000,   minorStep:null,          fmtMajor:d=>d.toLocaleDateString("es-ES",{day:"numeric",month:"short"}), fmtDay:d=>d.toLocaleDateString("es-ES",{day:"numeric",month:"short",year:"2-digit"}) },
  months: { label:"Meses",   pxPerHour:6,   windowH:90*24, majorStep:7*24*3600000, minorStep:null,          fmtMajor:d=>`S${Math.ceil(d.getDate()/7)}`,              fmtDay:d=>d.toLocaleDateString("es-ES",{month:"long",year:"numeric"}) },
};

function Timeline({envs, ress, repos, users, currentUser, onResClick, onNew, onResUpdate, policy, t}) {
  const [fCat,  setFCat]  = useState("ALL");
  const [fUser, setFUser] = useState("ALL");
  const [fJira, setFJira] = useState("");
  const [fRepo, setFRepo] = useState("ALL");
  const [winOff, setWinOff] = useState(-1);
  const [scaleKey, setScaleKey] = useState("days");

  const scale = SCALE_MODES[scaleKey];
  const pxH   = scale.pxPerHour;
  const WIN_H = scale.windowH;

  const scrollRef = useRef();
  const dragRef   = useRef(null);

  const winStart = useMemo(()=>{
    const d = new Date(); d.setHours(0,0,0,0);
    return new Date(d.getTime()+winOff*86400000);
  },[winOff]);
  const winEnd  = useMemo(()=>new Date(winStart.getTime()+WIN_H*3600000),[winStart,WIN_H]);
  const totalW  = WIN_H * pxH;

  useEffect(()=>{
    const nowX = (new Date()-winStart)/3600000*pxH;
    if(scrollRef.current) scrollRef.current.scrollLeft = Math.max(0, nowX-120);
  },[winStart, pxH]);

  const nowX = (new Date()-winStart)/3600000*pxH;

  const filtEnvs = useMemo(()=>envs.filter(e=>{
    if(e.isArchived) return false;
    if(fCat!=="ALL"&&e.category!==fCat) return false;
    return true;
  }),[envs,fCat]);

  const getEnvRes = envId => ress.filter(r=>{
    if(r.environmentId!==envId) return false;
    if(fUser!=="ALL"&&r.reservedByUserId!==fUser) return false;
    if(fJira&&!(r.jiraIssueKeys||[]).some(k=>k.toLowerCase().includes(fJira.toLowerCase()))) return false;
    if(fRepo!=="ALL"&&!r.selectedRepositoryIds.includes(fRepo)) return false;
    return new Date(r.plannedStart)<winEnd && new Date(r.plannedEnd)>winStart;
  });

  const majorTicks = useMemo(()=>{
    const ticks=[]; let d=new Date(winStart);
    if(scaleKey==="hours"){ d.setMinutes(0,0,0); }
    else if(scaleKey==="days"||scaleKey==="weeks"){ d.setHours(0,0,0,0); }
    else { d.setHours(0,0,0,0); while(d.getDay()!==1) d=new Date(d.getTime()+86400000); }
    while(d<winEnd){ticks.push(new Date(d));d=new Date(d.getTime()+scale.majorStep);}
    return ticks;
  },[winStart,winEnd,scaleKey,scale]);

  const minorTicks = useMemo(()=>{
    if(!scale.minorStep) return [];
    const ticks=[]; let d=new Date(winStart);
    while(d<winEnd){ticks.push(new Date(d));d=new Date(d.getTime()+scale.minorStep);}
    return ticks;
  },[winStart,winEnd,scale]);

  const startDrag = useCallback((e, res, type) => {
    if(!["Reserved","PolicyViolation","InUse"].includes(res.status)) return;
    const isAdmin = currentUser.role==="ADMIN";
    const isOwner = currentUser.id===res.reservedByUserId;
    if(!isOwner&&!isAdmin) return;
    e.preventDefault(); e.stopPropagation();
    const startX = e.clientX;
    const origStart = new Date(res.plannedStart);
    const origEnd   = new Date(res.plannedEnd);
    const dur = origEnd - origStart;
    let moved = false;

    dragRef.current = { type, resId:res.id, moved:false };

    const onMove = me => {
      const dx = me.clientX - startX;
      if(Math.abs(dx)<4) return;
      moved = true;
      dragRef.current.moved = true;
      const dh = Math.round((dx/pxH)/SNAP)*SNAP;
      if(type==="move") {
        dragRef.current.newStart = new Date(origStart.getTime()+dh*3600000);
        dragRef.current.newEnd   = new Date(origStart.getTime()+dh*3600000+dur);
      } else {
        dragRef.current.newEnd = new Date(origEnd.getTime()+dh*3600000);
      }
    };

    const onUp = () => {
      document.removeEventListener("mousemove", onMove);
      document.removeEventListener("mouseup", onUp);
      const st = dragRef.current;
      if(!st||!st.moved) { dragRef.current=null; return; }
      dragRef.current = null;
      const {newStart, newEnd} = st;

      if(type==="move" && newStart && newEnd) {
        if(newEnd<=new Date()){alert("Cannot move: end would be in the past.");return;}
        const ov = checkOverlap(ress, res.environmentId, newStart.toISOString(), newEnd.toISOString(), res.id);
        if(ov.length){alert(`Overlap with: ${ov.map(r=>r.jiraIssueKeys.join(",")).join(", ")}`);return;}
        onResUpdate(res.id, {plannedStart:newStart.toISOString(), plannedEnd:newEnd.toISOString()});
      } else if(type==="resize" && newEnd) {
        if(newEnd<=origStart){alert("End must be after start.");return;}
        if(newEnd<=new Date()){alert("End would be in the past.");return;}
        const env = envs.find(ev=>ev.id===res.environmentId);
        if(env && durH(origStart.toISOString(),newEnd.toISOString())>env.maxReservationDuration){
          alert(`Exceeds max ${env.maxReservationDuration}h`);return;
        }
        const ov = checkOverlap(ress, res.environmentId, res.plannedStart, newEnd.toISOString(), res.id);
        if(ov.length){alert("Resize would overlap another reservation.");return;}
        onResUpdate(res.id, {plannedEnd:newEnd.toISOString()});
      }
    };

    document.addEventListener("mousemove", onMove);
    document.addEventListener("mouseup", onUp);
  }, [currentUser, ress, envs, onResUpdate, pxH]);

  const handleBlockClick = (e, res) => {
    if(dragRef.current?.moved) return;
    onResClick(res);
  };

  const navStep = scaleKey==="hours" ? 1 : scaleKey==="days" ? 7 : scaleKey==="weeks" ? 28 : 90;

  return (
    <div style={{display:"flex",flexDirection:"column",height:"100%"}}>
      {/* Filters bar */}
      <div style={{display:"flex",flexWrap:"wrap",alignItems:"center",gap:6,padding:"8px 14px",borderBottom:`1px solid ${t.border}`,background:t.surface,flexShrink:0}}>
        <select style={{...I(t,{width:140})}} value={fCat} onChange={e=>setFCat(e.target.value)}>
          <option value="ALL">All Categories</option>
          <option value="DEV">DEV</option><option value="PRE">PRE</option><option value="STAGING">STAGING</option>
        </select>
        <select style={{...I(t,{width:130})}} value={fUser} onChange={e=>setFUser(e.target.value)}>
          <option value="ALL">All Users</option>
          {users.map(u=><option key={u.id} value={u.id}>{u.displayName||u.username}</option>)}
        </select>
        <input style={{...I(t,{width:120})}} placeholder="Jira…" value={fJira} onChange={e=>setFJira(e.target.value)}/>
        <select style={{...I(t,{width:150})}} value={fRepo} onChange={e=>setFRepo(e.target.value)}>
          <option value="ALL">All Repos</option>
          {repos.filter(r=>!r.isArchived).map(r=><option key={r.id} value={r.id}>{r.name}</option>)}
        </select>
        <div style={{marginLeft:"auto",display:"flex",gap:6}}>
          <button style={B(t,"ghost")} onClick={()=>setWinOff(w=>w-navStep)}>◀ atrás</button>
          <button style={B(t,"ghost")} onClick={()=>setWinOff(-1)}>Hoy</button>
          <button style={B(t,"ghost")} onClick={()=>setWinOff(w=>w+navStep)}>adelante ▶</button>
          <button style={{...B(t),marginLeft:8}} onClick={onNew}>+ Nueva reserva</button>
        </div>
      </div>

      <div style={{flex:1,overflow:"hidden",display:"flex"}}>
        {/* Left labels */}
        <div style={{width:LBL_W,flexShrink:0,borderRight:`1px solid ${t.border}`,background:t.surface}}>
          <div style={{height:HDR_H,borderBottom:`1px solid ${t.border}`,display:"flex",alignItems:"center",padding:"0 12px"}}>
            <span style={{fontSize:10,fontWeight:700,color:t.muted,textTransform:"uppercase",letterSpacing:"0.05em"}}>Environment</span>
          </div>
          {filtEnvs.map(env=>{
            const envColor = env.color||(CC[env.category]||CC.DEV).bar;
            return(
              <div key={env.id} style={{height:ROW_H,borderBottom:`1px solid ${t.border}`,display:"flex",alignItems:"center",padding:"0 10px",gap:8,
                background: env.isLocked ? "rgba(251,191,36,0.06)" : "transparent"}}>
                <div style={{width:3,height:26,borderRadius:2,background:envColor,flexShrink:0}}/>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontWeight:600,fontSize:12,color:t.text,lineHeight:1.2,display:"flex",alignItems:"center",gap:4}}>
                    {env.name}
                    {env.isLocked && <span title="Bloqueado por admin" style={{fontSize:11}}>🔒</span>}
                  </div>
                  <div style={{marginTop:3,display:"flex",alignItems:"center",gap:5}}>
                    <CatBadge cat={env.category}/>
                    {env.url && (
                      <a href={env.url} target="_blank" rel="noopener noreferrer"
                        title={`Abrir ${env.name}`}
                        style={{display:"inline-flex",alignItems:"center",gap:3,background:"rgba(99,102,241,0.15)",color:"#a5b4fc",
                          padding:"1px 6px",borderRadius:6,fontSize:10,fontWeight:600,textDecoration:"none",
                          border:"1px solid rgba(99,102,241,0.3)",lineHeight:1.5}}
                        onClick={e=>e.stopPropagation()}>
                        🔗 Open
                      </a>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Scrollable canvas */}
        <div style={{flex:1,overflowX:"auto",overflowY:"auto"}} ref={scrollRef}>
          <div style={{width:totalW,position:"relative",minHeight:HDR_H+filtEnvs.length*ROW_H}}>

            {/* Sticky 2-row header */}
            <div style={{height:HDR_H,position:"sticky",top:0,zIndex:20,background:t.surface,borderBottom:`1px solid ${t.border}`}}>
              <div style={{height:DAY_H,position:"relative",borderBottom:`1px solid ${t.border}`,overflow:"hidden"}}>
                {majorTicks.map((d,i)=>{
                  const x     = (d-winStart)/3600000*pxH;
                  const width = scale.majorStep/3600000*pxH;
                  const isNow = d.toDateString()===new Date().toDateString();
                  return(
                    <div key={i} style={{position:"absolute",left:x,width,top:0,height:DAY_H,
                      display:"flex",alignItems:"center",paddingLeft:6,
                      borderLeft:i>0?`1px solid ${t.dayLine}`:"none",
                      background:isNow?"rgba(99,102,241,0.07)":"transparent"}}>
                      <span style={{fontSize:10,fontWeight:500,color:t.text,whiteSpace:"nowrap",userSelect:"none",overflow:"hidden",textOverflow:"ellipsis"}}>
                        {scale.fmtDay(d)}
                        {isNow&&scaleKey==="days"&&<span style={{marginLeft:4,background:t.accent,color:"#fff",fontSize:9,padding:"1px 4px",borderRadius:4,fontWeight:700}}>HOY</span>}
                      </span>
                    </div>
                  );
                })}
              </div>
              <div style={{height:HR_H,position:"relative",overflow:"hidden"}}>
                {(minorTicks.length ? minorTicks : majorTicks).map((d,i)=>{
                  const x = (d-winStart)/3600000*pxH;
                  return(
                    <div key={i} style={{position:"absolute",left:x,top:0,height:"100%"}}>
                      <div style={{position:"absolute",left:0,top:0,width:1,height:"100%",background:t.hourLine}}/>
                      <span style={{position:"absolute",top:4,left:4,fontSize:10,color:t.muted+"90",userSelect:"none",whiteSpace:"nowrap"}}>
                        {scale.fmtMajor(d)}
                      </span>
                    </div>
                  );
                })}
                {nowX>0&&nowX<totalW&&(
                  <div style={{position:"absolute",left:nowX,top:0,height:"100%",width:2,background:"#ef4444",opacity:0.9}}>
                    <span style={{position:"absolute",top:2,left:4,fontSize:9,color:"#ef4444",fontWeight:700,whiteSpace:"nowrap"}}>NOW</span>
                  </div>
                )}
              </div>
            </div>

            {/* Rows */}
            {filtEnvs.map((env,ri)=>{
              const envRes   = getEnvRes(env.id);
              const envColor = env.color||(CC[env.category]||CC.DEV).bar;
              return(
                <div key={env.id} style={{position:"relative",height:ROW_H,borderBottom:`1px solid ${t.border}`,background:ri%2===0?"transparent":t.stripe}}>
                  {majorTicks.map((d,i)=>{
                    const x=(d-winStart)/3600000*pxH;
                    return <div key={i} style={{position:"absolute",left:x,top:0,width:1,height:"100%",background:t.dayLine}}/>;
                  })}
                  {minorTicks.map((d,i)=>{
                    const x=(d-winStart)/3600000*pxH;
                    return <div key={i} style={{position:"absolute",left:x,top:0,width:1,height:"100%",background:t.hourLine}}/>;
                  })}
                  {nowX>0&&nowX<totalW&&<div style={{position:"absolute",left:nowX,top:0,width:2,height:"100%",background:"#ef4444",opacity:0.4,zIndex:4}}/>}

                  {envRes.map(res=>{
                    const dispEnd  = res.status==="Completed"&&res.usageSession?.actualEnd?res.usageSession.actualEnd:res.plannedEnd;
                    const sx = (new Date(res.plannedStart)-winStart)/3600000*pxH;
                    const ex = (new Date(dispEnd)-winStart)/3600000*pxH;
                    const x  = Math.max(0,sx);
                    const w  = Math.max(10,ex-Math.max(0,sx));
                    const sc = SM[res.status]||SM.Completed;
                    const blockColor = ["Reserved","InUse","PolicyViolation"].includes(res.status) ? envColor : sc.color;
                    const ou = users.find(u=>u.id===res.reservedByUserId);
                    const draggable = ["Reserved","PolicyViolation","InUse"].includes(res.status);
                    const jLabel   = (res.jiraIssueKeys||[]).join(", ");

                    return(
                      <div key={res.id}
                        onMouseDown={e=>{ if(e.button!==0)return; startDrag(e,res,"move"); }}
                        onClick={e=>handleBlockClick(e,res)}
                        style={{
                          position:"absolute",left:x,width:w,top:6,height:ROW_H-12,
                          background:blockColor+"c0",borderLeft:`3px solid ${blockColor}`,
                          borderRadius:6,cursor:draggable?"grab":"pointer",
                          overflow:"hidden",padding:"3px 8px 3px 5px",zIndex:10,
                          boxShadow:`0 2px 8px ${blockColor}30`,transition:"box-shadow 0.12s",
                          userSelect:"none",
                        }}
                        onMouseEnter={e=>{e.currentTarget.style.boxShadow=`0 4px 16px ${blockColor}60`;e.currentTarget.style.zIndex=15;}}
                        onMouseLeave={e=>{e.currentTarget.style.boxShadow=`0 2px 8px ${blockColor}30`;e.currentTarget.style.zIndex=10;}}
                      >
                        <div style={{fontWeight:700,fontSize:11,color:"#fff",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{jLabel}</div>
                        <div style={{fontSize:10,color:"rgba(255,255,255,0.82)",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{ou?.displayName||ou?.username}{res.policyFlags?.exceedsMaxDuration?" ⚠️":""}</div>
                        {draggable&&w>20&&(
                          <div
                            onMouseDown={e=>{e.stopPropagation();startDrag(e,res,"resize");}}
                            onClick={e=>{e.stopPropagation();e.preventDefault();}}
                            style={{position:"absolute",right:0,top:0,width:10,height:"100%",cursor:"ew-resize",background:"rgba(255,255,255,0.15)",borderRadius:"0 6px 6px 0",zIndex:20,display:"flex",alignItems:"center",justifyContent:"center"}}
                            title="Arrastra para ajustar la fecha de fin"
                          >
                            <div style={{width:2,height:"55%",borderRadius:1,background:"rgba(255,255,255,0.5)"}}/>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Legend + Scale toggle */}
      <div style={{display:"flex",alignItems:"center",gap:14,padding:"6px 14px",borderTop:`1px solid ${t.border}`,background:t.surface,flexShrink:0,flexWrap:"wrap"}}>
        {Object.entries(SM).map(([k,v])=>(
          <div key={k} style={{display:"flex",alignItems:"center",gap:4}}>
            <div style={{width:9,height:9,borderRadius:2,background:v.color}}/><span style={{fontSize:11,color:t.muted}}>{v.label}</span>
          </div>
        ))}
        <span style={{fontSize:11,color:t.muted,marginLeft:"auto",marginRight:12}}>💡 Arrastra = mover · Borde = redimensionar · Click = detalle</span>
        <div style={{display:"flex",gap:2,background:t.card,border:`1px solid ${t.border}`,borderRadius:8,padding:2}}>
          {Object.entries(SCALE_MODES).map(([key,cfg])=>(
            <button key={key} onClick={()=>setScaleKey(key)}
              style={{background:scaleKey===key?t.accent:"transparent",color:scaleKey===key?"#fff":t.muted,
                border:"none",borderRadius:6,cursor:"pointer",fontSize:11,fontWeight:scaleKey===key?700:400,
                padding:"3px 10px",transition:"all 0.15s"}}
            >{cfg.label}</button>
          ))}
        </div>
      </div>
    </div>
  );
}

function ResList({ress, envs, repos, users, currentUser, onResClick, onNew, t}) {
  const vis = (currentUser.role==="ADMIN"?ress:ress.filter(r=>r.reservedByUserId===currentUser.id))
    .sort((a,b)=>new Date(b.plannedStart)-new Date(a.plannedStart));
  return(
    <div style={{padding:20,maxWidth:820,margin:"0 auto"}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:18}}>
        <h2 style={{fontWeight:700,fontSize:20,color:t.text}}>{currentUser.role==="ADMIN"?"All Reservations":"My Reservations"}</h2>
        <button style={B(t)} onClick={onNew}>+ New Reservation</button>
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:8}}>
        {vis.map(r=>{
          const env=envs.find(e=>e.id===r.environmentId);
          const ou=users.find(u=>u.id===r.reservedByUserId);
          const sc=SM[r.status]||SM.Completed;
          return(
            <div key={r.id} onClick={()=>onResClick(r)}
              style={{background:t.card,border:`1px solid ${t.border}`,borderLeft:`4px solid ${sc.color}`,borderRadius:10,padding:"12px 14px",cursor:"pointer",transition:"background 0.15s"}}
              onMouseEnter={e=>e.currentTarget.style.background=t.border}
              onMouseLeave={e=>e.currentTarget.style.background=t.card}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:4}}>
                <div style={{display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
                  <CatBadge cat={env?.category}/><span style={{fontWeight:600,color:t.text}}>{env?.name}</span>
                  <span style={{fontFamily:"'JetBrains Mono',monospace",fontSize:12,color:t.accent}}>{(r.jiraIssueKeys||[]).join(", ")}</span>
                </div>
                <SBadge status={r.status}/>
              </div>
              <div style={{fontSize:12,color:t.muted}}>
                {ou?.displayName||ou?.username} · {fmtDt(r.plannedStart)} → {fmtDt(r.plannedEnd)}
                {r.description&&<span style={{marginLeft:6}}>· {r.description.slice(0,50)}{r.description.length>50?"…":""}</span>}
                {r.policyFlags?.exceedsMaxDuration&&<span style={{color:"#f97316",marginLeft:8}}>⚠️ Policy violation</span>}
              </div>
            </div>
          );
        })}
        {vis.length===0&&<p style={{color:t.muted,textAlign:"center",marginTop:40}}>No reservations yet.</p>}
      </div>
    </div>
  );
}

